/**
 * Rate limiting using in-memory store (for basic protection)
 * In production, use Redis or Cloud Memorystore
 */
const rateLimitStore = new Map();
const RATE_LIMIT_WINDOW = 60000; // 1 minute
const RATE_LIMIT_MAX = 30; // 30 requests per minute per IP

function checkRateLimit(ip) {
  const now = Date.now();
  const key = ip || 'unknown';

  if (rateLimitStore.has(key)) {
    const entry = rateLimitStore.get(key);
    // Clean old entries
    entry.timestamps = entry.timestamps.filter(t => now - t < RATE_LIMIT_WINDOW);

    if (entry.timestamps.length >= RATE_LIMIT_MAX) {
      return false;
    }
    entry.timestamps.push(now);
  } else {
    rateLimitStore.set(key, { timestamps: [now] });
  }

  // Periodic cleanup of the store
  if (rateLimitStore.size > 10000) {
    for (const [k, v] of rateLimitStore) {
      v.timestamps = v.timestamps.filter(t => now - t < RATE_LIMIT_WINDOW);
      if (v.timestamps.length === 0) {
        rateLimitStore.delete(k);
      }
    }
  }

  return true;
}

